+        Subsystem::Specializer,
+        Subsystem::HostcallGate,
+    ] {
+        let json = serde_json::to_string(&s).unwrap();
+        let back: Subsystem = serde_json::from_str(&json).unwrap();
+        assert_eq!(s, back);
+    }
